var env = ENV;
var ABACASH_API_URL = "https://api.abacash.com.br";
async function createAbacashSubscription(payload2) {
  try {
    if (process.env.NODE_ENV === "development" || !env.abacashSkLive || env.abacashSkLive === "sk_test_mock") {
      console.log("[Abacash] Mock mode - returning test checkout URL");
      const mockSubscriptionId = `sub_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      const mockCheckoutUrl = `https://checkout.abacash.test/pay/${mockSubscriptionId}`;
      return {
        checkoutUrl: mockCheckoutUrl,
        subscriptionId: mockSubscriptionId
      };
    }
    if (!env.abacashSkLive) {
      throw new Error("ABACASH_SK_LIVE not configured for production");
    }
    const response = await fetch(`${ABACASH_API_URL}/subscriptions/create`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${env.abacashSkLive}`
      },
      body: JSON.stringify({
        customerId: payload2.customerId,
        planId: payload2.planId,
        planName: payload2.planName,
        amount: payload2.amount,
        billingCycle: payload2.billingCycle,
        returnUrl: payload2.returnUrl,
        notificationUrl: payload2.notificationUrl
      })
    });
    if (!response.ok) {
      const error47 = await response.json();
      throw new Error(`Abacash API error: ${error47.message || response.statusText}`);
    }
    const data2 = await response.json();
    return {
      checkoutUrl: data2.checkoutUrl,
      subscriptionId: data2.subscriptionId
    };
  } catch (error47) {
    console.error("[Abacash] Error creating subscription:", error47);
    throw error47;
  }
}
